const STEPS = ["Date","Time","Details","Pay"];
const ADDONS = [
  { key: "paddle", name: "Paddle rental", desc: "2 tournament paddles", price: 150 },
  { key: "ball", name: "Ball machine", desc: "Per session, balls incl.", price: 300 },
];

const BUSINESS_NAME = "Southside Dinkers";
