const PEAK_RATE = 300;

// Where you put your own GCash/Maya QR image. Drop a file named
// gcash-qr.jpg into the /public folder and this path will pick it up.
const GCASH_QR_SRC = "/gcash-qr.jpg";
const GCASH_NAME = "Caitlain Grace Patalinghug";
const GCASH_NUMBER = "0927 837 9384";
const FACEBOOK_URL = "https://www.facebook.com/profile.php?id=61591661855012";

function buildDates() {
  const today = todayInManila();
  const arr = [];
  for (let i = 0; i < 30; i++) {
    const d = new Date(today);
    d.setDate(today.getDate() + i);
    const wd = d.getDay();
    arr.push({
      idx: i,
      iso: isoLocal(d),
      dow: DOW[wd],
      dowFull: DOWFULL[wd],
      dom: d.getDate(),
      mon: MON[d.getMonth()],
      weekend: wd === 0 || wd === 6,
    });
  }
  return arr;
}

// Returns "today" as a Date object representing the current calendar date
// IN THE PHILIPPINES specifically -- not the visitor's device timezone.
// Without this, a customer browsing from a different timezone could see
// a different "today" than what's actually current at the courts.
function todayInManila() {
  const fmt = new Intl.DateTimeFormat("en-CA", {
    timeZone: "Asia/Manila",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
  });
  const parts = fmt.formatToParts(new Date());
  const y = Number(parts.find((p) => p.type === "year").value);
  const m = Number(parts.find((p) => p.type === "month").value);
  const d = Number(parts.find((p) => p.type === "day").value);
  return new Date(y, m - 1, d);
}

// Formats a date as YYYY-MM-DD using its LOCAL calendar date, not UTC.
// (toISOString() converts to UTC first, which silently shifts the date
// back by a day for any timezone ahead of UTC, like the Philippines --
// that bug caused bookings to save under the wrong date.)
function isoLocal(d) {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");
  return y + "-" + m + "-" + day;
}

function fmtHour(h) {
  const ap = h < 12 ? "AM" : "PM";
  let hh = h % 12;
  if (hh === 0) hh = 12;
  return hh + ":00 " + ap;
}
function isPeak(h) {
  return h >= 16;
}
function peso(n) {
  return "\u20b1" + n.toLocaleString("en-PH");
}
// Turns a list of picked hour-slots into readable ranges, e.g. two
// consecutive hours (16, 17) become "4:00 PM - 6:00 PM" instead of
// listing each hour separately.
function formatPickedRanges(pickedSlots) {
  if (!pickedSlots.length) return "\u2014";
  const hours = pickedSlots.map((s) => s.hour).sort((a, b) => a - b);
  const ranges = [];
  let start = hours[0];
  let prev = hours[0];
  for (let i = 1; i < hours.length; i++) {
    if (hours[i] === prev + 1) {
      prev = hours[i];
      continue;
    }
    ranges.push([start, prev]);
    start = hours[i];
    prev = hours[i];
  }
  ranges.push([start, prev]);
  return ranges.map(([s, e]) => fmtHour(s) + " - " + fmtHour(e + 1)).join(", ");
}

// Lists every picked hour as its own "9:00 AM - 10:00 AM" block, one per
// hour, instead of merging consecutive hours into a single range -- makes
// it unmistakable how many hours were actually booked at a glance.
function formatPickedHoursIndividually(pickedSlots) {
  if (!pickedSlots.length) return "\u2014";
  const sorted = [...pickedSlots].sort((a, b) => a.hour - b.hour);
  return sorted.map((s) => fmtHour(s.hour) + " - " + fmtHour(s.hour + 1)).join(", ");
}

export default function BookingFlow() {
  const dates = useMemo(buildDates, []);
  const [siteOpen, setSiteOpen] = useState(null); // null = still checking
  const [closedMessage, setClosedMessage] = useState("");
  const [step, setStep] = useState(1);
  const [dateIdx, setDateIdx] = useState(0);
  const [sel, setSel] = useState({});
  const [name, setName] = useState("");
  const [facebook, setFacebook] = useState("");
  const [email, setEmail] = useState("");
  const [phone, setPhone] = useState("");
  const [proofFile, setProofFile] = useState(null);
  const [proofError, setProofError] = useState("");
  const [qrBroken, setQrBroken] = useState(false);
  const [ref, setRef] = useState("");
  const [qrDataUrl, setQrDataUrl] = useState("");
  const [bookedHours, setBookedHours] = useState(new Set());
  const [loadingSlots, setLoadingSlots] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [errorMsg, setErrorMsg] = useState("");

  const day = dates[dateIdx];

  // Check whether bookings are open at all (owner controls this from /admin --
  // useful for a soft launch where the site is live but not yet bookable).
  useEffect(() => {
    supabase
      .from("site_settings")
      .select("is_open, closed_message")
      .eq("id", 1)
      .single()
      .then(({ data, error }) => {
        if (error || !data) {
          setSiteOpen(true); // fail open rather than lock everyone out on a glitch
          return;
        }
        setSiteOpen(data.is_open);
        setClosedMessage(data.closed_message);
      });
  }, []);

  // Pull real availability from Supabase every time the person is on the
  // Time step (not just when the date changes) -- this closes a gap where
  // a stale in-memory list let someone re-select an hour that was already
  // reserved by a pending (unpaid) booking, their own or someone else's.
  useEffect(() => {
    if (step !== 2) return;
    let cancelled = false;
    async function loadSlots() {
      setLoadingSlots(true);
      setErrorMsg("");
      const { data, error } = await supabase
        .from("booking_slots")
        .select("hour")
        .eq("court", COURT_LABEL)
        .eq("booking_date", day.iso);
      if (cancelled) return;
      if (error) {
        setErrorMsg("Couldn't load availability. Check your internet connection and try again.");
        setBookedHours(new Set());
      } else {
        setBookedHours(new Set(data.map((r) => r.hour)));
      }
      setLoadingSlots(false);
    }
    loadSlots();
    return () => {
      cancelled = true;
    };
  }, [day.iso, step]);

  const slots = useMemo(() => {
    const arr = [];
    for (let h = 6; h < 24; h++) {
      const peak = isPeak(h);
      const booked = bookedHours.has(h);
      const key = "h" + h;
      arr.push({ key, hour: h, time: fmtHour(h), peak, booked, price: peak ? PEAK_RATE : OFF_PEAK_RATE });
    }
    return arr;
  }, [bookedHours]);

  const picked = slots.filter((s) => sel[s.key] && !s.booked);
  const total = picked.reduce((t, s) => t + s.price, 0);

  function toggleSlot(s) {
    if (s.booked) return;
    setSel((p) => {
      const m = { ...p };
      if (m[s.key]) delete m[s.key];
      else m[s.key] = true;
      return m;
    });
  }

  function handleProofSelect(e) {
    const file = e.target.files && e.target.files[0];
    if (!file) {
      setProofFile(null);
      setProofError("");
      return;
    }
    const MAX_BYTES = 2 * 1024 * 1024;
    if (file.size > MAX_BYTES) {
      setProofFile(null);
      setProofError("That file is too big -- please choose a screenshot under 2MB.");
      e.target.value = "";
      return;
    }
    if (!file.type.startsWith("image/")) {
      setProofFile(null);
      setProofError("Please choose an image file (screenshot).");
      e.target.value = "";
      return;
    }
    setProofFile(file);
    setProofError("");
  }

  function canNext() {
    if (step === 2) return picked.length > 0 && !loadingSlots;
    if (step === 3) return name.trim() && facebook.trim() && email.trim() && phone.trim();
    if (step === 4) return !!proofFile && !proofError && !submitting;
    return true;
  }

  async function goNext() {
    if (!canNext()) return;
    if (step === 4) {
      setSubmitting(true);
      setErrorMsg("");
      const newRef = "SD-" + Math.floor(1000 + Math.random() * 9000);

      // Upload the payment screenshot first.
      const ext = (proofFile.name.split(".").pop() || "jpg").toLowerCase();
      const path = `${newRef}-${Date.now()}.${ext}`;
      const { error: uploadError } = await supabase.storage
        .from("payment-proofs")
        .upload(path, proofFile, { contentType: proofFile.type || "image/jpeg" });
      if (uploadError) {
        setSubmitting(false);
        setErrorMsg("Couldn't upload your screenshot. Please check your connection and try again.");
        return;
      }
      const { data: urlData } = supabase.storage.from("payment-proofs").getPublicUrl(path);
      const proofUrl = urlData.publicUrl;

      const { error } = await supabase.rpc("create_booking", {
        p_ref: newRef,
        p_court: COURT_LABEL,
        p_date: day.iso,
        p_hours: picked.map((s) => s.hour),
        p_addons: [],
        p_name: name,
        p_facebook: facebook,
        p_email: email,
        p_phone: phone,
        p_total: total,
        p_payment_reference: proofUrl,
      });
      setSubmitting(false);
      if (error) {
        setErrorMsg(error.message || "Something went wrong saving your booking. Please try again.");
        // Someone may have grabbed a slot first -- refresh availability.
        const { data } = await supabase
          .from("booking_slots")
          .select("hour")
          .eq("court", COURT_LABEL)
          .eq("booking_date", day.iso);
        if (data) setBookedHours(new Set(data.map((r) => r.hour)));
        return;
      }
      setRef(newRef);
      setStep(5);
      QRCode.toDataURL(newRef, { width: 200, margin: 1, color: { dark: "#1B2E57", light: "#FFFFFF" } })
        .then(setQrDataUrl)
        .catch(() => setQrDataUrl(""));
      sendPendingEmail({
        to_name: name,
        to_email: email,
        booking_ref: newRef,
        booking_date: day.dowFull + ", " + day.mon + " " + day.dom,
        booking_times: formatPickedHoursIndividually(picked),
        booking_total: peso(total),
        court_label: COURT_LABEL,
      });
    } else {
      setStep((s) => Math.min(5, s + 1));
    }
  }
  function goBack() {
    setErrorMsg("");
    setStep((s) => Math.max(1, s - 1));
  }
  function resetAll() {
    setStep(1);
    setDateIdx(0);
    setSel({});
    setName("");
    setFacebook("");
    setEmail("");
    setPhone("");
    setProofFile(null);
    setProofError("");
    setRef("");
    setErrorMsg("");
  }

  const pct = Math.round(((step - 1) / 3) * 100);
  const showStepCount = step <= 4;
  const showFooter = step <= 4;
  const showBack = step > 1 && step <= 4;
  const showRunningTotal = step >= 2 && step <= 3;
  const nextDisabled = !canNext();

  const dateRowStyle = (isSel) => ({
    display: "flex", alignItems: "center", justifyContent: "space-between", width: "100%",
    padding: "14px 15px", borderRadius: 14, cursor: "pointer", fontFamily: "inherit",
    background: isSel ? COLORS.navy : "#fff", color: isSel ? "#fff" : COLORS.navy,
    border: `1px solid ${isSel ? COLORS.navy : COLORS.border}`,
    boxShadow: isSel ? "0 8px 20px -8px rgba(16,27,48,.5)" : "0 2px 8px -3px rgba(16,27,48,.12)",
  });
  const slotStyle = (s, isSel) => {
    const base = { display: "flex", flexDirection: "column", gap: 3, alignItems: "flex-start", justifyContent: "center", minHeight: 58, padding: "9px 12px", borderRadius: 13, fontFamily: "inherit", textAlign: "left" };
    if (s.booked) return { ...base, background: COLORS.bookedBg, border: `1px solid ${COLORS.bookedBorder}`, color: COLORS.bookedText, cursor: "default" };
    if (isSel) return { ...base, background: COLORS.navy, border: `1px solid ${COLORS.navy}`, color: "#fff", cursor: "pointer", boxShadow: "0 6px 16px rgba(16,27,48,.28)" };
    if (s.peak) return { ...base, background: COLORS.peakBg, border: `1px solid ${COLORS.peakBorder}`, color: COLORS.peakText, cursor: "pointer", boxShadow: "0 2px 8px -3px rgba(16,27,48,.1)" };
    return { ...base, background: "#fff", border: `1px solid ${COLORS.border}`, color: COLORS.navy, cursor: "pointer", boxShadow: "0 2px 8px -3px rgba(16,27,48,.1)" };
  };
  const addonStyle = (on) => ({ display: "flex", alignItems: "center", justifyContent: "space-between", gap: 10, width: "100%", padding: 14, borderRadius: 16, cursor: "pointer", fontFamily: "inherit", background: "#fff", border: `2px solid ${on ? COLORS.navy : COLORS.border}` });
  const checkStyle = (on) => ({ display: "flex", alignItems: "center", justifyContent: "center", width: 28, height: 28, borderRadius: 8, flex: "none", fontSize: 16, fontWeight: 800, background: on ? COLORS.green : COLORS.bookedBg, color: on ? COLORS.greenText : "transparent", border: on ? "none" : `1px solid ${COLORS.border}` });
  const inputStyle = { width: "100%", padding: "14px 15px", border: `1px solid ${COLORS.border}`, borderRadius: 13, background: "#fff", fontSize: 17, color: COLORS.navy };
  const fieldLabel = { display: "block", fontSize: 13, fontWeight: 700, textTransform: "uppercase", letterSpacing: ".5px", color: COLORS.mutedSoft, marginBottom: 7 };
  const h1Style = { fontFamily: "'Manrope',sans-serif", fontWeight: 800, fontSize: 32, letterSpacing: "-.3px", lineHeight: 1.08 };
  const subStyle = { fontSize: 16, color: COLORS.muted, margin: "5px 0 18px" };

  // Still checking whether the site is open -- show nothing flashy, just a blank moment.
  if (siteOpen === null) {
    return <div style={{ minHeight: "100vh", background: "#fff" }} />;
  }

  // Site is intentionally closed (soft launch, maintenance, etc.)
  if (siteOpen === false) {
    return (
      <div style={{ minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", padding: "28px 16px", fontFamily: "'Manrope', sans-serif", color: COLORS.navy, background: "#FFFFFF" }}>
        <div style={{ maxWidth: 380, textAlign: "center" }}>
          <img src={LOGO_SRC} alt="SD" style={{ height: 64, width: "auto", borderRadius: 12, margin: "0 auto 20px" }} />
          <div style={{ fontFamily: "'Manrope',sans-serif", fontWeight: 800, fontSize: 26, marginBottom: 10 }}>{BUSINESS_NAME}</div>
          <div style={{ fontSize: 16, color: COLORS.muted, lineHeight: 1.6 }}>{closedMessage}</div>
        </div>
      </div>
    );
  }

  return (
    <div style={{ minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", padding: "28px 16px", fontFamily: "'Manrope', sans-serif", color: COLORS.navy, background: "#FFFFFF", backgroundImage: `radial-gradient(circle at 1px 1px, rgba(30,48,80,.06) 1px, transparent 0)`, backgroundSize: "26px 26px" }}>
      <style>{`
        * { box-sizing: border-box; }
        .sd-input:focus { outline: none; border-color: ${COLORS.navy} !important; box-shadow: 0 0 0 3px rgba(30,48,80,.08); }
        .sd-scroll::-webkit-scrollbar { width: 6px; height: 6px; }
        .sd-scroll::-webkit-scrollbar-thumb { background: #D7DBD1; border-radius: 6px; }
        @keyframes sdpop { 0% { transform: scale(.5); opacity: 0; } 60% { transform: scale(1.12); } 100% { transform: scale(1); opacity: 1; } }
      `}</style>

      <div style={{ width: "min(452px,96vw)", height: "min(872px,94vh)", display: "flex", flexDirection: "column", background: COLORS.bg, borderRadius: 30, overflow: "hidden", boxShadow: "0 30px 70px -34px rgba(16,27,48,.35)", border: `1px solid ${COLORS.border}` }}>
        {/* Header */}
        <div style={{ background: `linear-gradient(135deg, #2C4468 0%, ${COLORS.navy} 60%, ${COLORS.navyDarker} 100%)`, color: "#fff", padding: "22px 22px 18px", flex: "none" }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
              <img src={LOGO_SRC} alt="SD" style={{ height: 52, width: "auto", borderRadius: 10, background: "#fff", padding: 3, boxShadow: "0 6px 16px -4px rgba(0,0,0,.4)" }} />
              <div>
                <div style={{ fontFamily: "'Manrope',sans-serif", fontWeight: 800, fontSize: 21, letterSpacing: "1.5px", textTransform: "uppercase", lineHeight: 1 }}>{BUSINESS_NAME}</div>
                <div style={{ fontSize: 13, color: "#9DB0D6", marginTop: 4 }}>{COURT_LABEL}</div>
              </div>
            </div>
            {showStepCount && <span style={{ fontFamily: "'Manrope',sans-serif", fontWeight: 700, fontSize: 13, letterSpacing: "1px", textTransform: "uppercase", color: "#9DB0D6" }}>Step {step} / 4</span>}
          </div>
          {showStepCount && (
            <div style={{ marginTop: 16 }}>
              <div style={{ height: 4, borderRadius: 4, background: "rgba(255,255,255,.14)", overflow: "hidden" }}>
                <div style={{ height: "100%", width: pct + "%", background: COLORS.green, borderRadius: 4, transition: "width .3s ease" }} />
              </div>
              <div style={{ display: "flex", justifyContent: "space-between", marginTop: 8 }}>
                {STEPS.map((label, i) => {
                  const n = i + 1;
                  const color = n === step ? COLORS.green : n < step ? "#fff" : "rgba(157,176,214,.55)";
                  return <span key={label} style={{ fontSize: 11, fontWeight: 700, textTransform: "uppercase", letterSpacing: ".5px", color }}>{label}</span>;
                })}
              </div>
            </div>
          )}
        </div>

        {/* Body */}
        <div className="sd-scroll" style={{ flex: 1, overflowY: "auto", padding: "22px 22px 10px" }}>
          {errorMsg && (
            <div style={{ background: "#FDECEC", border: "1px solid #F5C6C6", color: "#8A2323", borderRadius: 12, padding: "10px 13px", fontSize: 13, marginBottom: 14 }}>{errorMsg}</div>
          )}

          {step === 1 && (
            <div>
              <div style={h1Style}><Calendar size={22} aria-hidden="true" style={{ verticalAlign: "-3px", marginRight: 8, color: "#8CC63F" }} />When do you want to play?</div>
              <div style={{ height: 16 }} />
              <div style={{ display: "flex", flexDirection: "column", gap: 9 }}>
                {dates.map((d) => (
                  <button key={d.idx} onClick={() => { setDateIdx(d.idx); setSel({}); }} style={dateRowStyle(d.idx === dateIdx)}>
                    <span style={{ display: "flex", alignItems: "baseline", gap: 10 }}>
                      <span style={{ fontFamily: "'Manrope',sans-serif", fontWeight: 800, fontSize: 22 }}>{d.dow}</span>
                      <span style={{ fontSize: 16, opacity: 0.75 }}>{d.mon} {d.dom}</span>
                    </span>
                    <span style={{ fontSize: 12, fontWeight: 700, padding: "5px 11px", borderRadius: 20, background: d.idx === dateIdx ? "rgba(140,198,63,.25)" : COLORS.bookedBg, color: d.idx === dateIdx ? "#C8E89A" : COLORS.mutedSoft }}>
                      {d.weekend ? "Weekend" : "Weekday"}
                    </span>
                  </button>
                ))}
              </div>
            </div>
          )}

          {step === 2 && (
            <div>
              <div style={h1Style}><Clock size={22} aria-hidden="true" style={{ verticalAlign: "-3px", marginRight: 8, color: "#8CC63F" }} />Choose your time</div>
              <div style={{ fontSize: 14, color: COLORS.muted, margin: "5px 0 14px" }}>
                {day.dowFull}, {day.mon} {day.dom} · {loadingSlots ? "checking availability\u2026" : "tap one or more hours."}
              </div>
              <div style={{ display: "flex", gap: 14, alignItems: "center", fontSize: 13, color: COLORS.mutedSoft, marginBottom: 12 }}>
                <span style={{ display: "flex", alignItems: "center", gap: 6 }}><span style={{ width: 12, height: 12, borderRadius: 3, background: "#fff", border: `1px solid ${COLORS.border}` }} />Off-peak</span>
                <span style={{ display: "flex", alignItems: "center", gap: 6 }}><span style={{ width: 12, height: 12, borderRadius: 3, background: COLORS.peakBg, border: `1px solid ${COLORS.peakBorder}` }} />Peak</span>
                <span style={{ display: "flex", alignItems: "center", gap: 6 }}><span style={{ width: 12, height: 12, borderRadius: 3, background: COLORS.bookedBg }} />Booked</span>
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(2,1fr)", gap: 9, opacity: loadingSlots ? 0.5 : 1 }}>
                {slots.map((s) => (
                  <button key={s.key} disabled={s.booked || loadingSlots} onClick={() => toggleSlot(s)} style={slotStyle(s, !!sel[s.key] && !s.booked)}>
                    <span style={{ fontFamily: "'Manrope',sans-serif", fontWeight: 700, fontSize: 17 }}>{s.time} - {fmtHour(s.hour + 1)}</span>
                    <span style={{ fontSize: 13, fontWeight: 700, letterSpacing: ".3px", textTransform: "uppercase" }}>{s.booked ? "Booked" : "Available"}</span>
                    <span style={{ fontSize: 12, fontWeight: 600, opacity: 0.75 }}>{s.booked ? "" : peso(s.price) + (s.peak ? " \u00b7 Peak" : "")}</span>
                  </button>
                ))}
              </div>
            </div>
          )}

          {step === 3 && (
            <div>
              <div style={h1Style}><UserRound size={22} aria-hidden="true" style={{ verticalAlign: "-3px", marginRight: 8, color: "#8CC63F" }} />Your details</div>
              <div style={subStyle}>All fields are required — we'll send your confirmation here.</div>
              <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
                <label style={{ display: "block" }}>
                  <span style={fieldLabel}>Full name</span>
                  <input className="sd-input" value={name} onChange={(e) => setName(e.target.value)} placeholder="Jordan Cruz" style={inputStyle} />
                </label>
                <label style={{ display: "block" }}>
                  <span style={fieldLabel}>Facebook name</span>
                  <input className="sd-input" value={facebook} onChange={(e) => setFacebook(e.target.value)} placeholder="Jordan Cruz" style={inputStyle} />
                </label>
                <label style={{ display: "block" }}>
                  <span style={fieldLabel}>Email</span>
                  <input className="sd-input" value={email} onChange={(e) => setEmail(e.target.value)} placeholder="you@email.com" style={inputStyle} />
                </label>
                <label style={{ display: "block" }}>
                  <span style={fieldLabel}>Contact number</span>
                  <input className="sd-input" value={phone} onChange={(e) => setPhone(e.target.value)} placeholder="0917 000 0000" style={inputStyle} />
                </label>
              </div>
            </div>
          )}

          {step === 4 && (
            <div>
              <div style={h1Style}><Wallet size={22} aria-hidden="true" style={{ verticalAlign: "-3px", marginRight: 8, color: "#8CC63F" }} />Review &amp; pay</div>
              <div style={{ fontSize: 16, color: COLORS.muted, margin: "5px 0 16px" }}>{day.dowFull}, {day.mon} {day.dom}</div>

              <div style={{ background: "#fff", border: `1px solid ${COLORS.borderSoft}`, borderRadius: 16, padding: 17, marginBottom: 16 }}>
                <div style={{ display: "flex", flexDirection: "column", gap: 9 }}>
                  {picked.map((s) => (
                    <div key={s.key} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", fontSize: 16 }}>
                      <span style={{ fontWeight: 600 }}>{s.time} - {fmtHour(s.hour + 1)}</span>
                      <span style={{ fontSize: 13, color: COLORS.mutedSoft, flex: 1, marginLeft: 8 }}>{s.peak ? "Peak" : "Off-peak"}</span>
                      <span style={{ fontWeight: 700, fontFamily: "'Manrope',sans-serif" }}>{peso(s.price)}</span>
                    </div>
                  ))}
                </div>
                <div style={{ height: 1, background: COLORS.borderSoft, margin: "13px 0" }} />
                <div style={{ display: "flex", alignItems: "baseline", justifyContent: "space-between" }}>
                  <span style={{ fontFamily: "'Manrope',sans-serif", fontWeight: 800, textTransform: "uppercase", letterSpacing: ".5px", fontSize: 18 }}>Total</span>
                  <span style={{ fontFamily: "'Manrope',sans-serif", fontWeight: 800, fontSize: 28, lineHeight: 1 }}>{peso(total)}</span>
                </div>
              </div>

              <div style={{ background: "#fff", border: `1px solid ${COLORS.borderSoft}`, borderRadius: 16, padding: 18, textAlign: "center", marginBottom: 16 }}>
                <div style={{ fontFamily: "'Manrope',sans-serif", fontWeight: 800, fontSize: 14, textTransform: "uppercase", letterSpacing: ".5px", marginBottom: 10 }}>
                  Scan to pay via GCash
                </div>
                <img
                  src={GCASH_QR_SRC}
                  alt="GCash QR code"
                  style={{ width: 180, height: 180, objectFit: "contain", margin: "0 auto", display: qrBroken ? "none" : "block", border: `1px solid ${COLORS.border}`, borderRadius: 12, background: "#fafafa" }}
                  onError={() => setQrBroken(true)}
                  onLoad={() => setQrBroken(false)}
                />
                {qrBroken && (
                  <div style={{ fontSize: 12, color: "#8A2323", background: "#FDECEC", border: "1px solid #F5C6C6", borderRadius: 10, padding: "8px 10px" }}>
                    QR image not found. Make sure <code>gcash-qr.jpg</code> is inside the <code>public</code> folder, spelled exactly that way (check it isn't secretly named <code>gcash-qr.jpg.jpg</code>).
                  </div>
                )}
                <div style={{ fontSize: 13, color: COLORS.muted, marginTop: 10 }}>{GCASH_NAME} · {GCASH_NUMBER}</div>
                <div style={{ fontSize: 12, color: COLORS.mutedSoft, marginTop: 4 }}>Pay {peso(total)}, then upload proof below.</div>
              </div>

              <label style={{ display: "block" }}>
                <span style={fieldLabel}>Upload screenshot or proof of your payment confirmation</span>
                <input className="sd-input" type="file" accept="image/*" onChange={handleProofSelect} style={inputStyle} />
              </label>
              <div style={{ fontSize: 11, color: COLORS.mutedSoft, marginTop: 6 }}>Max file size: 2MB.</div>
              {proofError && (
                <div style={{ fontSize: 12, color: "#8A2323", marginTop: 8 }}>{proofError}</div>
              )}
              {proofFile && !proofError && (
                <div style={{ fontSize: 12, color: COLORS.green, marginTop: 8, fontWeight: 600 }}>✓ {proofFile.name}</div>
              )}
              <div style={{ fontSize: 11, color: COLORS.mutedSoft, marginTop: 8 }}>
                We'll confirm your slot once we verify the payment — usually within a few hours.
              </div>
            </div>
          )}

          {step === 5 && (
            <div style={{ textAlign: "center", padding: "30px 6px 10px" }}>
              <div style={{ width: 78, height: 78, borderRadius: "50%", background: COLORS.green, color: COLORS.greenText, display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 18px", fontSize: 40, fontWeight: 800, animation: "sdpop .45s ease-out" }}>✓</div>
              <div style={{ fontFamily: "'Manrope',sans-serif", fontWeight: 800, fontSize: 30 }}>Booking request received!</div>
              <div style={{ fontSize: 14, color: COLORS.muted, marginTop: 4 }}>Here's what happens next.</div>

              <div style={{ background: "#FFF7E0", border: "1px solid #F0D98A", borderRadius: 14, padding: "14px 16px", margin: "18px 0 0", textAlign: "left" }}>
                <div style={{ fontFamily: "'Manrope',sans-serif", fontWeight: 800, fontSize: 15, textTransform: "uppercase", letterSpacing: ".5px", color: "#7A5D00" }}>
                  This is NOT a confirmed booking yet
                </div>
                <div style={{ fontSize: 13, color: "#7A5D00", marginTop: 4 }}>
                  We're verifying your payment. You'll get a second email once that's done -- your slot is already reserved in the meantime.
                </div>
              </div>

              <div style={{ background: "#fff", borderRadius: 16, margin: "16px 0 16px", textAlign: "left", boxShadow: "0 14px 32px -14px rgba(16,27,48,.3)", overflow: "hidden" }}>
                <div style={{ padding: "18px 18px 0" }}>
                  <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 12 }}>
                    <span style={{ fontSize: 12, textTransform: "uppercase", letterSpacing: "1px", color: COLORS.mutedSoft }}>Booking ref</span>
                    <span style={{ fontFamily: "'Manrope',sans-serif", fontWeight: 800, fontSize: 18, letterSpacing: "1px" }}>{ref}</span>
                  </div>
                  <div style={{ fontWeight: 700, fontSize: 15 }}>{day.dowFull}, {day.mon} {day.dom}</div>
                  <div style={{ fontSize: 14, color: COLORS.muted, marginTop: 2 }}>{formatPickedHoursIndividually(picked)}</div>
                </div>
                <div style={{ position: "relative", margin: "16px 0 0" }}>
                  <div style={{ borderTop: `1px dashed ${COLORS.border}` }} />
                  <div style={{ position: "absolute", left: -10, top: -10, width: 20, height: 20, borderRadius: "50%", background: COLORS.bg }} />
                  <div style={{ position: "absolute", right: -10, top: -10, width: 20, height: 20, borderRadius: "50%", background: COLORS.bg }} />
                </div>
                <div style={{ padding: "16px 18px 18px", display: "flex", alignItems: "center", justifyContent: "space-between", gap: 12 }}>
                  <div style={{ flex: 1 }}>
                    <div style={{ display: "flex", alignItems: "baseline", justifyContent: "space-between" }}>
                      <span style={{ fontFamily: "'Manrope',sans-serif", fontWeight: 800, textTransform: "uppercase", letterSpacing: ".5px" }}>Total</span>
                      <span style={{ fontFamily: "'Manrope',sans-serif", fontWeight: 800, fontSize: 24 }}>{peso(total)}</span>
                    </div>
                  </div>
                  {qrDataUrl && <img src={qrDataUrl} alt="QR code for booking reference" style={{ width: 64, height: 64, borderRadius: 8, flex: "none" }} />}
                </div>
              </div>

              <div style={{ fontSize: 11, color: COLORS.mutedSoft, textAlign: "left", lineHeight: 1.5 }}>
                <strong>Cancellation policy:</strong> Please give at least 24 hours' notice to cancel or reschedule. Cancellations received less than 12 hours before your booking time will not be entitled to a refund. To cancel or reschedule, message us on <a href={FACEBOOK_URL} target="_blank" rel="noopener noreferrer" style={{ color: COLORS.navy, fontWeight: 700 }}>Facebook</a>.
              </div>

              <button onClick={resetAll} style={{ marginTop: 14, width: "100%", padding: 10, border: "none", background: "none", color: COLORS.muted, fontWeight: 600, fontSize: 14, cursor: "pointer", textDecoration: "underline" }}>
                Book another slot
              </button>
            </div>
          )}
        </div>

        {/* Footer */}
        {showFooter && (
          <div style={{ flex: "none", padding: "14px 22px 18px", borderTop: `1px solid ${COLORS.borderSoft}`, background: "#fff" }}>
            {showRunningTotal && (
              <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 11 }}>
                <span style={{ fontSize: 14, color: COLORS.muted }}>{picked.length} {picked.length === 1 ? "hour selected" : "hours selected"}</span>
                <span style={{ fontFamily: "'Manrope',sans-serif", fontWeight: 800, fontSize: 22 }}>{peso(total)}</span>
              </div>
            )}
            <div style={{ display: "flex", gap: 10 }}>
              {showBack && (
                <button onClick={goBack} style={{ padding: "15px 22px", border: `1px solid ${COLORS.border}`, borderRadius: 14, background: "#fff", color: COLORS.navy, fontFamily: "'Manrope',sans-serif", fontWeight: 800, letterSpacing: "1px", textTransform: "uppercase", fontSize: 17, cursor: "pointer" }}>
                  Back
                </button>
              )}
              <button onClick={goNext} disabled={nextDisabled} style={{ flex: 1, padding: 15, borderRadius: 14, fontFamily: "'Manrope',sans-serif", fontWeight: 800, letterSpacing: "1px", textTransform: "uppercase", fontSize: 18, border: "none", background: nextDisabled ? "#D7DBD1" : COLORS.navy, color: nextDisabled ? "#9AA79D" : "#fff", cursor: nextDisabled ? "not-allowed" : "pointer", boxShadow: nextDisabled ? "none" : "0 8px 20px -6px rgba(16,27,48,.5)" }}>
                {step === 4 ? (submitting ? "Saving\u2026" : "Confirm booking") : "Continue"}
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
